  class SecureRandomSource{
    nextInteger(maxExclusive){
      const max=clampInt(maxExclusive,0,1,0x100000000);
      const range=0x100000000;
      const limit=range-(range%max);
      const data=new Uint32Array(1);
      do{crypto.getRandomValues(data);}while(data[0]>=limit);
      return data[0]%max;
    }
    weightedChoice(items){
      const total=items.reduce((sum,item)=>sum+clampInt(item.weight,0,0,1e9),0);
      if(total<=0) throw new Error('Reward weights must total more than zero.');
      let roll=this.nextInteger(total);
      for(let i=0;i<items.length;i++){
        roll-=clampInt(items[i].weight,0,0,1e9);
        if(roll<0) return {item:items[i],index:i};
      }
      return {item:items[items.length-1],index:items.length-1};
    }
  }
