  function numberCell(n){return numgrid.querySelector('[data-num="'+n+'"]');}
  function relativePoint(elements){
    const base=numgrid.getBoundingClientRect();
    const rects=elements.map(el=>el.getBoundingClientRect());
    return {x:rects.reduce((s,r)=>s+r.left+r.width/2,0)/rects.length-base.left,y:rects.reduce((s,r)=>s+r.top+r.height/2,0)/rects.length-base.top};
  }
  function addInsideZone(id,x,y,kind,label,extraClass=''){
    const def=getBetDefinition(id);if(!def||renderedInsideIds.has(id))return;
    renderedInsideIds.add(id);
    const b=document.createElement('button');b.type='button';b.className='inside-zone '+kind+(extraClass?' '+extraClass:'');b.dataset.bet=id;b.dataset.zoneType=kind;
    b.style.left=x+'px';b.style.top=y+'px';b.setAttribute('aria-label',(label||def.label)+', covers '+def.numbers.join(', ')+', pays '+def.payout+' to 1');
    b.title=(label||def.label)+' — '+def.numbers.join(', ');
    insideLayer.appendChild(b);
  }
  let renderedInsideIds=new Set();
  function buildInsideZones(){
    insideLayer.innerHTML='';renderedInsideIds=new Set();
    const gridRect=numgrid.getBoundingClientRect();
    if(gridRect.width<100||gridRect.height<50)return;
    const zero=numberCell(0);
    for(let street=0;street<12;street++){
      const base=street*3+1;
      const cells=[numberCell(base),numberCell(base+1),numberCell(base+2)];
      const centers=cells.map(el=>relativePoint([el]));
      addInsideZone(makeInsideId('split',[base,base+1]),(centers[0].x+centers[1].x)/2,(centers[0].y+centers[1].y)/2,'split',null,'split-horizontal');
      addInsideZone(makeInsideId('split',[base+1,base+2]),(centers[1].x+centers[2].x)/2,(centers[1].y+centers[2].y)/2,'split',null,'split-horizontal');
      /* v8.1: street tap zones removed — the detached bet spots on the board's bottom edge above the dozens row are no longer placeable. */
      if(street<11){
        const next=[numberCell(base+3),numberCell(base+4),numberCell(base+5)];
        const nextCenters=next.map(el=>relativePoint([el]));
        for(let row=0;row<3;row++) addInsideZone(makeInsideId('split',[base+row,base+3+row]),(centers[row].x+nextCenters[row].x)/2,centers[row].y,'split',null,'split-vertical');
        addInsideZone(makeInsideId('corner',[base,base+1,base+3,base+4]),(centers[0].x+nextCenters[0].x)/2,(centers[0].y+centers[1].y)/2,'corner');
        addInsideZone(makeInsideId('corner',[base+1,base+2,base+4,base+5]),(centers[1].x+nextCenters[1].x)/2,(centers[1].y+centers[2].y)/2,'corner');
        /* v8.1: six-line tap zones removed along the bottom edge. */
      }
    }
    const z=zero.getBoundingClientRect(), p1=relativePoint([numberCell(1)]),p2=relativePoint([numberCell(2)]),p3=relativePoint([numberCell(3)]);
    const zx=z.right-gridRect.left;
    addInsideZone(makeInsideId('split',[0,1]),zx,(p1.y+(z.top+z.height/2-gridRect.top))/2,'split','Zero and 1 split','split-vertical');
    addInsideZone(makeInsideId('split',[0,2]),zx,p2.y,'split','Zero and 2 split','split-vertical');
    addInsideZone(makeInsideId('split',[0,3]),zx,(p3.y+(z.top+z.height/2-gridRect.top))/2,'split','Zero and 3 split','split-vertical');
    addInsideZone(makeInsideId('trio',[0,1,2]),zx,(p1.y+p2.y)/2,'trio','Zero 1 2 trio');
    addInsideZone(makeInsideId('trio',[0,2,3]),zx,(p2.y+p3.y)/2,'trio','Zero 2 3 trio');
    /* v8.1: first-four tap zone removed from the bottom edge. */
    render();
  }
  const scheduleZoneBuild=()=>{clearTimeout(zoneResizeTimer);zoneResizeTimer=setTimeout(buildInsideZones,80);};
  window.addEventListener('resize',scheduleZoneBuild,{passive:true});

  /* ========================= BET UI ========================= */
