    if(!Object.keys(betSnapshot).length){phase='bet';setBoardNoMore(false);restartEmptyRoundTimer();return;}
    if(Object.keys(betSnapshot).length){lastBets=JSON.parse(JSON.stringify(betSnapshot));if(autoBet)autoBetTemplate=JSON.parse(JSON.stringify(betSnapshot));}
    const winningPocketIndex=rng.nextInteger(N),winningNumber=ORDER[winningPocketIndex],roundId=uid('round');
    currentRoundSession=Object.freeze({roundId,winningPocketIndex,winningNumber,winningColour:colorOf(winningNumber),selectedAt:Date.now(),betSnapshot,totalBet:Object.values(betSnapshot).reduce((a,b)=>a+b,0)});
