    Object.freeze({name:'Silver',goal:15000000,rewardGold:250000,rewardTokens:1}),
    Object.freeze({name:'Gold',goal:40000000,rewardGold:500000,rewardTokens:2}),
    Object.freeze({name:'Platinum',goal:100000000,rewardGold:1000000,rewardTokens:2}),
    Object.freeze({name:'Diamond',goal:250000000,rewardGold:2500000,rewardTokens:3}),
    Object.freeze({name:'Master',goal:500000000,rewardGold:5000000,rewardTokens:3}),
    Object.freeze({name:'Grandmaster',goal:1000000000,rewardGold:10000000,rewardTokens:5}),
    Object.freeze({name:'Velvet Legend',goal:null,rewardGold:25000000,rewardTokens:7})
