  /* Local save integrity detects accidental corruption and casual editing.
     Purchased currency must still be verified by the native store/backend; client-only data is never tamper-proof. */
  function stableStringify(value){
    if(value===null||typeof value!=='object')return JSON.stringify(value);
    if(Array.isArray(value))return '['+value.map(stableStringify).join(',')+']';
    return '{'+Object.keys(value).sort().map(key=>JSON.stringify(key)+':'+stableStringify(value[key])).join(',')+'}';
  }
  function saveIntegrity(payload){
    const input=stableStringify(payload);let hash=2166136261;
    for(let i=0;i<input.length;i++){hash^=input.charCodeAt(i);hash=Math.imul(hash,16777619);}
    return (hash>>>0).toString(16).padStart(8,'0');
  }
  function verifySaveIntegrity(data){
    if(!data||typeof data!=='object'||typeof data.integrity!=='string')return true; // legacy migration
    const payload=Object.assign({},data);delete payload.integrity;
    return saveIntegrity(payload)===data.integrity;
  }

  /* ========================= PROFESSIONAL PLAYER PROFILE + FIREBASE ========================= */
  function createLocalPlayerId(){const bytes=new Uint8Array(8);crypto.getRandomValues(bytes);return 'VR-'+Array.from(bytes,b=>b.toString(16).padStart(2,'0')).join('').toUpperCase();}
  async function createSignedInPlayerId(firebaseUid){
    const source='velvet-roulette:'+String(firebaseUid||'');
    try{const digest=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(source));return 'VR-'+Array.from(new Uint8Array(digest).slice(0,8),b=>b.toString(16).padStart(2,'0')).join('').toUpperCase();}
    catch(_){let a=2166136261,b=2246822519;for(let i=0;i<source.length;i++){a=Math.imul(a^source.charCodeAt(i),16777619);b=Math.imul(b+source.charCodeAt(i),3266489917);}return 'VR-'+((a>>>0).toString(16)+(b>>>0).toString(16)).padStart(16,'0').slice(0,16).toUpperCase();}
  }
  function cleanPhotoUrl(value){const s=String(value||'').trim();return /^https:\/\//i.test(s)?s.slice(0,1000):'';}
  function sanitiseAccount(value){
    const source=value&&typeof value==='object'?value:{};const localId=String(source.localId||source.id||createLocalPlayerId()).slice(0,80);const mode=source.mode==='signed_in'?'signed_in':'guest';const id=mode==='signed_in'?String(source.id||localId).slice(0,160):localId;const rawName=String(source.name||'Velvet Player').replace(/[<>\u0000-\u001f]/g,'').trim().replace(/\s+/g,' ').slice(0,20);const legacyAvatar=String(source.avatar||'user');const migratedAvatar=legacyAvatar==='V'?'user':legacyAvatar==='7'?'roulette':legacyAvatar;const avatar=ALLOWED_AVATARS.has(migratedAvatar)?migratedAvatar:'user';
    return{mode,id,localId,name:rawName||'Velvet Player',email:String(source.email||'').slice(0,160),avatar,photoUrl:mode==='signed_in'?cleanPhotoUrl(source.photoUrl):''};
  }
  function loadAccount(){try{accountState=sanitiseAccount(JSON.parse(localStorage.getItem(ACCOUNT_KEY)||'null'));}catch(_){accountState=sanitiseAccount(null);}saveAccount();}
  function saveAccount(){try{localStorage.setItem(ACCOUNT_KEY,JSON.stringify(accountState));}catch(_){}updatePlayerHubUI();}
  function loadPreferences(){try{const p=JSON.parse(localStorage.getItem(PREFS_KEY)||'{}');hapticsOn=p.hapticsOn!==false;performanceMode=p.performanceMode===true;pauseInBackground=p.pauseInBackground!==false;}catch(_){hapticsOn=true;performanceMode=false;pauseInBackground=true;}applyPreferences();}
