    if($('profileConnectBtn')){$('profileConnectBtn').textContent=signed?'GOOGLE CONNECTED':'CONNECT GOOGLE';$('profileConnectBtn').disabled=signed;}if($('settingsGoogleBtn')){$('settingsGoogleBtn').textContent=signed?'GOOGLE CONNECTED':'CONNECT GOOGLE';$('settingsGoogleBtn').disabled=signed;}if($('settingsSignOutBtn'))$('settingsSignOutBtn').hidden=!signed;
    if($('settingsAccountText'))$('settingsAccountText').textContent=signed?'Signed in as '+(accountState.email||accountState.name)+'. Your Google photo is used in the game profile.':'Playing as '+accountState.name+' with a local guest avatar. Settings remain available in every account state.';
    if($('settingsDeleteBtn'))$('settingsDeleteBtn').textContent=signed?'DELETE VELVET ACCOUNT':'RESET LOCAL GUEST PROFILE';if($('avatarPicker'))$('avatarPicker').hidden=signed;
    document.querySelectorAll('#avatarPicker [data-avatar]').forEach(b=>b.classList.toggle('selected',b.dataset.avatar===fallback));applyPreferences();updateAccountGateUI();
