  function saveNickname(){const input=$('profileNameInput'),status=$('playerHubStatus');if(accountState.mode==='signed_in'){status.textContent='Google controls the signed-in display name.';return;}const value=String(input&&input.value||'').replace(/[<>\u0000-\u001f]/g,'').trim().replace(/\s+/g,' ').slice(0,20);if(value.length<2){status.textContent='Player name must contain at least 2 characters.';return;}accountState=sanitiseAccount(Object.assign({},accountState,{name:value}));saveAccount();status.textContent='Guest player name saved.';}
