    const action=data.lastBetAction;if(action&&getBetDefinition(String(action.id))&&clampInt(action.amount)>0)lastBetAction={id:String(action.id),amount:clampInt(action.amount)};else lastBetAction=null;
    autoBetTemplate=data.autoBetTemplate&&typeof data.autoBetTemplate==='object'?Object.fromEntries(Object.entries(data.autoBetTemplate).filter(([id,v])=>getBetDefinition(id)&&clampInt(v)>0).map(([id,v])=>[id,clampInt(v)])):null;
    if(!autoBetTemplate&&lastBets)autoBetTemplate=JSON.parse(JSON.stringify(lastBets));autoBet=!!data.autoBet&&!!autoBetTemplate;
