    transactionJournal=Array.isArray(data.transactionJournal)?data.transactionJournal.slice(-DAILY_CONFIG.maxTransactionJournal).filter(tx=>tx&&typeof tx.idempotencyKey==='string'):[];
    claimedRewardIds=new Set(Array.isArray(data.claimedRewardIds)?data.claimedRewardIds.map(String).slice(-250):[]);settledRoundIds=new Set(Array.isArray(data.settledRoundIds)?data.settledRoundIds.map(String).slice(-100):[]);
