    if(reward.type==='coins'){$('dailyResultTitle').textContent='YOU WIN!';$('dailyResultAmount').textContent=fmt(reward.amount)+' CHIPS';$('dailyResultSub').textContent=session.convertedFromRespin?'Maximum respins reached — awarded '+fmt(reward.amount)+' chips.':'Your daily chip bonus is ready.';$('dailyResultAction').textContent='CLAIM REWARD';winSound();}
