  /* ========================= DAILY LOGIN PERKS ========================= */
  function perkClaimAvailable(){return localDaySerial(trustedNow())>lastPerkClaimDay;}
  function nextPerkDay(){
    const today=localDaySerial(trustedNow());
    if(lastPerkClaimDay===today)return Math.max(1,Math.min(7,loginStreak||1));
    if(lastPerkClaimDay===today-1)return Math.max(1,Math.min(7,(loginStreak||0)+1));
    return 1;
  }
  function updatePerksButton(){
    const button=$('perksBtn'),state=$('perksState');if(!button||!state)return;
    const ready=perkClaimAvailable(),day=nextPerkDay();button.classList.toggle('ready',ready);state.textContent=ready?'CLAIM':'DAY '+Math.max(1,loginStreak);
    button.setAttribute('aria-label',ready?('Claim Day '+day+' login perk'):('Daily perk claimed; current streak Day '+Math.max(1,loginStreak)));
  }
  function perkRewardSummary(reward){
    const parts=[];if(reward.coins)parts.push(fmt(reward.coins)+' chips');if(reward.gems)parts.push(reward.gems+' diamonds');if(reward.tokens)parts.push(reward.tokens+' Free Spin'+(reward.tokens===1?'':'s'));return parts.join(' + ');
  }
  function renderPerks(){
    const grid=$('perksGrid'),status=$('perksStatus'),claim=$('perksClaim');if(!grid||!status||!claim)return;
    const ready=perkClaimAvailable(),activeDay=nextPerkDay(),today=localDaySerial(trustedNow());grid.innerHTML='';
    DAILY_PERKS.forEach(reward=>{
      const card=document.createElement('div');card.className='perk-day'+(reward.day===activeDay?' active':'')+(reward.day<activeDay&&ready?' claimed':'')+(reward.day===7?' day7':'');
      if(!ready&&reward.day===loginStreak)card.classList.add('claimed');
      const label=document.createElement('div');label.className='perk-label';label.textContent='DAY '+reward.day;
      const art=document.createElement('div');art.className='perk-art';art.textContent=reward.icon;
      const amount=document.createElement('div');amount.className='perk-reward';amount.textContent=reward.label;
      card.append(label,art,amount);if(reward.repeat){const repeat=document.createElement('div');repeat.className='perk-repeat';repeat.textContent='Repeats after Day 7';card.appendChild(repeat);}
      grid.appendChild(card);
    });
    if(ready){const reward=DAILY_PERKS[activeDay-1];status.textContent='Day '+activeDay+' is ready: '+perkRewardSummary(reward)+'.';claim.textContent='CLAIM DAY '+activeDay;claim.disabled=false;}
    else{status.textContent=perkClaimedStatusText();claim.textContent='CLAIMED TODAY';claim.disabled=true;}
    updatePerksButton();
  }
  function msUntilNextPerk(){const now=trustedNow(),d=new Date(now);return Math.max(0,new Date(d.getFullYear(),d.getMonth(),d.getDate()+1,0,0,0,0).getTime()-now);}
  function perkClaimedStatusText(){return 'Today’s perk is claimed. Next perk unlocks in '+countdownText(msUntilNextPerk())+'.';}
