  /* ========================= DIAGNOSTIC RULE TESTS ========================= */
  function runRuleDiagnostics(){
    const failures=[];const expect=(condition,message)=>{if(!condition)failures.push(message);};
    expect(ORDER.length===37&&new Set(ORDER).size===37,'European wheel must contain 37 unique pockets');
    expect(colorOf(0)==='green','0 must be green');RED_NUMBERS.forEach(n=>expect(colorOf(n)==='red',n+' must be red'));BLACK_NUMBERS.forEach(n=>expect(colorOf(n)==='black',n+' must be black'));
    expect(isBetWinner('dozen3',34),'34 must win third dozen');expect(isBetWinner('col-bot',34),'34 must win first column');expect(!isBetWinner('col-top',34),'34 must not win third column');expect(isBetWinner('red',34),'34 must be red');
    expect(winFor(makeInsideId('split',[12,15]),12)===17,'12/15 split must pay 17:1');expect(!VALID_INSIDE_IDS.has(makeInsideId('split',[12,16])),'12/16 must be invalid');expect(winFor(makeInsideId('corner',[1,2,4,5]),5)===8,'1/2/4/5 corner must pay 8:1');expect(winFor(makeInsideId('first4',[0,1,2,3]),0)===8,'first four must include zero');
    expect(VALID_INSIDE_IDS.has(makeInsideId('split',[1,2])),'1/2 split must exist');expect(VALID_INSIDE_IDS.has(makeInsideId('split',[1,4])),'1/4 split must exist');
    expect(VALID_INSIDE_IDS.size===108,'Inside betting map must contain 108 unique legal zones');
    ['red','black','odd','even','low','high','dozen1','dozen2','dozen3','col-bot','col-mid','col-top'].forEach(id=>expect(!isBetWinner(id,0),id+' must lose on zero'));
    const sample=calculateSettlement({winningNumber:34,totalBet:410,betSnapshot:Object.freeze({dozen3:100,'col-bot':100,red:100,black:100,'n-34':10})});
    expect(sample.grossReturn===1160,'34 sample settlement must return 1,160 chips');expect(sample.netProfit===750,'34 sample settlement net profit must be 750 chips');
    const mixedPresentation=getResultPresentation({winningNumber:7,totalBet:300,grossReturn:200,netProfit:-100,winningBetIds:['red']});
    expect(mixedPresentation.kind==='win'&&mixedPresentation.amount.includes('200'),'Any winning bet must show a win and the returned winning amount, even when the round net is negative');
    const statTest=computeHotCold([{number:12},{number:7},{number:12},{number:0},{number:12},{number:7}]);
    expect(statTest.hot[0].number===12&&statTest.hot[0].count===3,'Hot numbers must be ordered by highest frequency');
    expect(statTest.cold.every(item=>item.count===0),'Cold numbers must prefer the least-frequent unhit pockets');
    const rewardIds=FREE_SPIN_REWARDS.filter(r=>r.type==='gems').map(r=>r.id).sort();expect(rewardIds.join(',')==='gems_10,gems_5','Daily wheel must have only 5 and 10 gem rewards');
    const g5=FREE_SPIN_REWARDS.findIndex(r=>r.id==='gems_5'),g10=FREE_SPIN_REWARDS.findIndex(r=>r.id==='gems_10');expect(Math.abs(g5-g10)===FREE_SPIN_REWARDS.length/2,'5 and 10 gem sectors must be opposite');
    const rankTest=levelInfo(100000);expect(Math.abs(rankTest.pct-.1)<1e-9&&rankTest.progressText==='100K / 1M','100K of 1M must render as 10 percent');
    for(let i=0;i<128;i++){const value=rng.nextInteger(37);expect(Number.isInteger(value)&&value>=0&&value<37,'Secure random result must stay in range');}
    expect(DAILY_PERKS.length===7&&DAILY_PERKS[6].repeat===true,'Daily perks must contain seven days and repeat Day 7');expect(typeof showBalanceWarning==='function','Balance warning helper must exist');expect(typeof signInWithGoogle==='function','Account sign-in shell must exist');
    const criticalButtons=['spinBtn','repeatBtn','autoBtn','dailyBtn','dailySpinBtn','perksBtn','perksClaim','accountBtn','googleSignInBtn','guestBtn','boardBuyGold','boardBuyDiamonds','doubleBtn','undoBtn','clearBtn'];criticalButtons.forEach(id=>expect(!!$(id),id+' must exist'));
    document.documentElement.dataset.selfTest=failures.length?'failed':'passed';
    if(failures.length){console.error('Velvet Roulette functional diagnostics failed:',failures);flash('A game self-check failed. Reload before playing.');spinBtn.disabled=true;$('dailySpinBtn').disabled=true;}
    else console.info('Velvet Roulette: roulette, payout, daily-wheel and progression diagnostics passed.');
    return failures;
  }


