  function runLoadingScreen(){
    const screen=$('loadingScreen'),fill=$('loadingFill'),track=$('loadingTrack');
    if(!screen){showPlayScreen('missing-loading-screen');return;}
    let finished=false;
    const finishLoading=()=>{
      if(finished)return;
      finished=true;
      if(fill)fill.style.width='100%';
      if(track){track.style.setProperty('--loading-progress','100%');track.setAttribute('aria-valuenow','100');}
      screen.classList.add('complete');
      setTimeout(()=>showPlayScreen('loading-complete'),420);
    };
    const fallback=setTimeout(finishLoading,7000);
    const started=performance.now(),duration=3200;
    function frame(now){
      const p=Math.min(1,(now-started)/duration),e=1-Math.pow(1-p,3),percent=Math.round(e*100);
      if(fill)fill.style.width=percent+'%';
      if(track){track.style.setProperty('--loading-progress',percent+'%');track.setAttribute('aria-valuenow',String(percent));}
      if(p<1)requestAnimationFrame(frame);else{clearTimeout(fallback);finishLoading();}
    }
    requestAnimationFrame(frame);
  }
